import { LOGIN_REQUEST, LOGIN_SUCCESS, LOGIN_FAIL, LOAD_REQUEST, LOAD_SUCCESS, LOAD_FAIL, LOGOUT_SUCCESS, LOGOUT_FAIL } from "../constants/userConstants";

const userReducer = (state = { user: {} }, action) => {
    switch (action.type) {
        case LOGIN_REQUEST:
        case LOAD_REQUEST:
            return {
                ...state,
                isloading: true,
            }

        case LOGIN_SUCCESS:
        case LOAD_SUCCESS:
            return {
                ...state,
                isloading: false,
                user: action.payload
            }

        case LOGIN_FAIL:
        case LOAD_FAIL:
            return {
                ...state,
                isloading: false,
                user: null,
            }

        case LOGOUT_SUCCESS:
            return {
                isloading: false,
                user: null,
            }

        case LOGOUT_FAIL:
            return {
                ...state,
                isloading: false,
            }


        default:
            return {
                ...state
            }
    }
}

export default userReducer;