import React, { useState, useRef } from 'react'
import './masterQr.scss'
import { QrReader } from "@blackbox-vision/react-qr-reader";
import { useTorchLight } from "@blackbox-vision/use-torch-light";
import { useNavigate } from 'react-router-dom';
import { Button } from '@mui/material';

import AddIcon from '@mui/icons-material/Add';
import RemoveIcon from '@mui/icons-material/Remove';
import FlashOnIcon from '@mui/icons-material/FlashOn';
import FlashOffIcon from '@mui/icons-material/FlashOff';
import ClearIcon from '@mui/icons-material/Clear';
import qr from '../../assests/qr2.gif'
import qr1 from '../../assests/qr1.jpg'


const MasterQr = () => {

    const [quantity, setQuantity] = useState(0);
    const navigate = useNavigate();

    const [screen1, setScreen1] = useState(true);
    const [screen2, setScreen2] = useState(false);

    const next = () =>{
        setScreen1(false);
        setScreen2(true);
    }


    //////////////////////////////////////////////////////////
    const streamRef = useRef(null);
    const [data, setData] = useState(null);

    const [on, toggle] = useTorchLight(streamRef.current, {
        debug: true,
        vibrate: 200
    });
    //////////////////////////////////////////////////////////

    const masterData = {
        id: 1,
        status: true,
        items: [
            { id: 1, state: false },
            { id: 2, state: true },
            { id: 3, state: false },
            { id: 4, state: true },
        ]
    }


    const dec = () => {
        if (quantity > 0) {
            setQuantity(Number(quantity) - 1);
        }
    }
    const inc = () => {
        setQuantity(Number(quantity) + 1);
    }

    const handleQuantity = (e) => {
        const result = e.target.value.replace(/\D/g, '');
        setQuantity(result);
    }

    const goback = () => {
        navigate(-1);
    }

    ///////////////////////////// Scanner /////////////////////////////////////////////

    const handleScan = (data) => {
        if (data) {
            console.log(data);
        }
    }


    const handleError = (err) => {
        console.error(err);
    }


    /////////////////////////////////////////////////////////////////////////////

    return (
        <>
            <div className='main'>
                <div className='masterQr'>

                    <div className='title'>Scan Master QR
                        <Button variant='contained' onClick={goback} className='but'><ClearIcon fontSize='small' /></Button>
                    </div>

                    <div id='qrBox'>
                        <img src={qr} alt="" />
                    </div>

                    <QrReader
                        facingMode={"environment"}
                        key="environment"
                        constraints={{ facingMode: 'environment' }}
                        onLoad={({ stream }) => (streamRef.current = stream)}
                        onScan={(data) => { handleScan(data); setData(data) }}
                        onError={handleError}
                    />

                    <div className='inner'>
                        <div className='torchBox'> <Button onClick={toggle} id='torch' variant='contained'> {on ? <FlashOffIcon /> : <FlashOnIcon />} </Button> </div>
                        <div id="line"></div>


                        {screen1 ? <div className='screen1'>
                            <div className='heading1'>Enter number of products in Master Box</div>
                            <div className='grid1'>
                                <div className='d1'>
                                    <div className='val'>
                                        <input type="text" name="" value={quantity} onChange={handleQuantity} />
                                        <div id='line1'></div>
                                    </div>
                                    <div className='text'>Quantity</div>
                                </div>

                                <div className='d2'> <Button variant='contained' className='bt3' onClick={dec}><RemoveIcon fontSize='medium' /></Button> </div>
                                <div className='d2'> <Button variant='contained' className='bt3' onClick={inc}><AddIcon fontSize='medium' /></Button> </div>
                            </div>

                            <div className='btnBox'><Button className='bt' variant='contained' onClick={next} >Next</Button></div>
                        </div> : null}



                        {screen2 ? <div className='screen2'>

                            <div className='heading2'>
                                Master QR
                                <div>Products Added - 0</div>
                            </div>

                            <div className='masterBox'>

                                <div className='master'>
                                    <div id='line2'></div>
                                    <div id='box'>

                                        <div> <img src={qr1} alt="" />
                                            <Button className='del' variant='contained'><ClearIcon style={{ fontSize: "14px" }} /></Button>
                                        </div>

                                    </div>
                                    <div id='data'>Master QR</div>
                                </div>

                                <div className='scroll'>

                                    {masterData.items.map((val, index) => {
                                        return (
                                            <div className='qr' key={index}>
                                                <div className='item'>
                                                    {val.state ? <div> <img src={qr1} alt="" />
                                                        <Button className='del' variant='contained'><ClearIcon style={{ fontSize: "14px" }} /></Button>
                                                    </div> : null}
                                                </div>
                                                <section>{val.id}</section>
                                            </div>
                                        );
                                    })}

                                </div>

                            </div>

                            <div className='btnBox'><Button className='bt' variant='contained'>Next</Button></div>


                        </div> : null}


                    </div>

                </div>
            </div>
        </>
    )
}

export default MasterQr