import axios from "axios";
import { LOGIN_REQUEST, LOGIN_SUCCESS, LOGIN_FAIL, LOAD_REQUEST, LOAD_SUCCESS, LOAD_FAIL, LOGOUT_SUCCESS, LOGOUT_FAIL } from "../constants/userConstants";

export const loginUser = (userData) => async (dispatch) => {
    try {
        dispatch({ type: LOGIN_REQUEST });
        const config = { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } };
        const { data } = await axios.post('https://api-dev.billfy.in/gateKeeper_login', userData, config);
        localStorage.setItem('token', `${data.accessToken}`);
        localStorage.setItem('userAuth', true);
        console.log(data);
        dispatch({ type: LOGIN_SUCCESS, payload: data.user });
    } catch (error) {
        console.log(error);
    }
}

