export const logoutUser = () => async (dispatch) => {
    try {
        localStorage.removeItem('token');
        localStorage.setItem('userAuth', false);
        dispatch({type:LOGOUT_SUCCESS});
    } catch (error) {
        console.log(error);
    }
}