import React from 'react'
import './home.scss'
import img1 from '../../assests/b2.png'
import img2 from '../../assests/b1.png'
import { Button } from '@mui/material'
import { useNavigate } from 'react-router-dom'

import qr3 from '../../assests/qr3.gif';
import { useDispatch } from 'react-redux'
import { logoutUser } from '../../actions/userAction'
import { useEffect } from 'react'

const Home = () => {

  const navigate = useNavigate();

  const printQr = () => {
    navigate('/generate_Qr');
  }
  const masterQr = () => {
    navigate('/master_Qr');
  }


  //////////// -------- REDUX ---------- ///////////
  const userAuth = localStorage.getItem('userAuth');
  useEffect(() => {
    if (userAuth == 'false') {
      navigate('/login');
    }
    console.log(userAuth);
  }, [userAuth]);

  const dispatch = useDispatch();
  const logout = () => {
    dispatch(logoutUser());
    navigate('/login');
  }

  return (
    <>
      <div className='main'>
        <div className='gateKeeperHome'>
          <div className='header'><button onClick={logout}>logout</button></div>

          <div className='inner'>

            <div className='box1'>
              <div className="img1"><img src={img1} alt="" /></div>
              <Button variant='contained' className='bt' onClick={printQr}>Print QR code</Button>
              <div className='aniBox'><img src={qr3} alt="" /></div>
            </div>

            <div className='box2'>
              <div className="img1"><img src={img2} alt="" /></div>
              <Button variant='contained' className='bt' onClick={masterQr} >Link Master QR</Button>
              <div className='aniBox'><img src={qr3} alt="" /></div>
            </div>

          </div>

        </div>
      </div>
    </>
  )
}

export default Home