import React, { useEffect, useState } from 'react'
import './printQr.scss'
import ClearIcon from '@mui/icons-material/Clear';
import AddIcon from '@mui/icons-material/Add';
import RemoveIcon from '@mui/icons-material/Remove';
import ArrowDropDownIcon from '@mui/icons-material/ArrowDropDown';
import { Button } from '@mui/material';
import { useNavigate } from 'react-router-dom';

import anim1 from '../../assests/anim1.gif'
import anim2 from '../../assests/anim2.gif'
import mix from '../../assests/mix.png'
import Product from '../../components/product/Product';

const PrintQr = () => {

    const navigate = useNavigate();

    const goback = () => {
        navigate(-1);
    }

    useEffect(() => {
        setTimeout(() => {
            document.getElementById("inner").style.bottom = '0px';
        }, 10);
    });

    const download = () => {
        navigate(-1);
    }

    const [state1, setState1] = useState(true);
    const [state2, setState2] = useState(false);
    const [state3, setState3] = useState(false);

    const generateQr = () => {
        setState1(false);
        setState2(true);

        setTimeout(() => {
            setState2(false);
            setState3(true);
        }, 8000);
    }

    const [quantity, setQuantity] = useState();

    const dec = () => {
        if (quantity > 0) {
            setQuantity(Number(quantity) - 1);
        }
    }
    const inc = () => {
        if (!quantity) {
            setQuantity(1);
        } else {
            setQuantity(Number(quantity) + 1);
        }
    }
    const handleQuantity = (e) => {
        const result = e.target.value.replace(/\D/g, '');
        setQuantity(result);
    }

    const [masterQr, setMasterQr] = useState(true);
    const [productQr, setProductQr] = useState(false);
    const activeMasterQr = () => {
        setMasterQr(true);
        setProductQr(false);
    }

    const activeProductQr = () => {
        setMasterQr(false);
        setProductQr(true);
    }

    const [pdf, setPdf] = useState(true);
    const [excel, setExcel] = useState(false);
    const activePdf = () => {
        setExcel(false);
        setPdf(true);
    }

    const activeExcel = () => {
        setExcel(true);
        setPdf(false);
    }

    const [showProduct, setProduct] = useState(false);
    const [productName, setProductName] = useState("Select Product");

    const Array = [
        { name: "Product Name", category: "category", img: mix },
        { name: "Syska LED", category: "category", img: mix },
        { name: "Mixer", category: "category", img: mix },
        { name: "Cooker", category: "category", img: mix },
        { name: "Boiler", category: "category", img: mix },
        { name: "Glasses", category: "category", img: mix },
        { name: "Mobile Phone", category: "category", img: mix },
    ]

    const closeAll = () => {
        setProduct(false);
    }

    const fun = (data) => {
        setProductName(data.name);
        closeAll();
    }


    return (
        <>
            <div className='main'>
                <div className='printQr' onClick={closeAll}>
                    <div id='inner'>

                        <div id="line"></div>

                        <div className='innerScroll'>

                            {state1 ? <div>

                                <button className='btn but1' onClick={goback}><ClearIcon /></button>

                                <div className='head'>
                                    <div>Print QR code</div>
                                    <section>
                                        Select a product and enter number of QR code
                                        you want to print and click download
                                    </section>
                                </div>


                                <form>

                                    <div className="form-group">
                                        <label>QR Type</label>
                                        <div className='grid2'>
                                            <div><Button className={masterQr ? 'bt1' : 'bt2'} onClick={activeMasterQr} variant='contained'>Product QR</Button></div>
                                            <div><Button className={productQr ? 'bt1' : 'bt2'} onClick={activeProductQr} variant='contained'>Master QR</Button> </div>
                                        </div>
                                    </div>

                                    {masterQr ? <div className="form-group select">
                                        <label>Product</label>
                                        <input type="text" class="form-control" readOnly style={{ cursor: "pointer" }} placeholder={productName} onClick={(e) => { e.stopPropagation(); setProduct(!showProduct) }} />
                                        <ArrowDropDownIcon className='icon' />

                                        {showProduct ? <div className='selectProduct' onClick={(e) => e.stopPropagation()}>

                                            {Array.map((val, index) => {
                                                return (
                                                    <Product key={index} data={val} fun={fun} />
                                                );
                                            })}

                                        </div> : null}

                                    </div> : null}

                                    <div className="form-group">
                                        <label>Quantity</label>
                                        <div className='grid1'>
                                            <div className='d1'> <input type="text" class="form-control" aria-describedby="emailHelp" placeholder="Quantity" value={quantity} onChange={handleQuantity} />  </div>
                                            <div className='d2'> <Button variant='contained' className='bt3' onClick={dec}><RemoveIcon fontSize='medium' /></Button> </div>
                                            <div className='d2'> <Button variant='contained' className='bt3' onClick={inc}><AddIcon fontSize='medium' /></Button> </div>
                                        </div>
                                    </div>

                                    <div className="form-group">
                                        <label>Formate</label>
                                        <div className='grid2'>
                                            <div><Button className={pdf ? 'bt1' : 'bt2'} onClick={activePdf} variant='contained'>PDF</Button></div>
                                            <div><Button className={excel ? 'bt1' : 'bt2'} onClick={activeExcel} variant='contained'>Excel</Button> </div>
                                        </div>
                                    </div>


                                </form>

                                <div className='genBox'> <Button className='generate' variant='contained' onClick={generateQr}>Generate QR</Button> </div>

                            </div> : null}

                            {state2 ? <div className='animation1'>
                                <img src={anim1} alt="" />
                                <div>Hold on! QR File is Generating</div>
                            </div> : null}

                            {state3 ? <div className='animation1'>
                                <img src={anim2} alt="" />
                                <div>QR File is ready to Download</div>
                            </div> : null}
                            {state3 ? <div className='download' onClick={download}> <Button className='bt' variant='contained'>Download File</Button> </div> : null}


                        </div>
                    </div>
                </div>
            </div>
        </>
    )
}

export default PrintQr